  var photos = ['abn-photo1', 'abn-photo2', 'abn-photo3'].filter(function (id) {
    return document.getElementById(id).classList.contains('captured');
  }).length;
  var item = WF.addAbn({
    checkPoint: cp,
    observed: obs,
    cause: cause,
    remarks: remarks,
    machine: machine,
    priority: prio,
    photos: photos
  });
  closeAbn();
  // Book on calendar
  var now = new Date();
  var key = "".concat(now.getFullYear(), "-").concat(String(now.getMonth() + 1).padStart(2, '0'), "-").concat(String(now.getDate()).padStart(2, '0'));
  if (!ckEvents[key]) ckEvents[key] = [];
