function toggleNode(id) {
  var ch = document.getElementById('ch-' + id);
  var arr = document.getElementById('arr-' + id);
  if (!ch) return;
  var open = ch.classList.toggle('open');
  if (arr) arr.classList.toggle('open', open);
}
function selectPanel(id, context) {
  document.querySelectorAll('.detail-panel').forEach(function (p) {
    return p.classList.remove('active');
  });
  var target = document.getElementById(id);
  if (target) target.classList.add('active');
  // Context-aware panels
  if (id === 'p-other-ra' && context) {
    target.innerHTML = buildRoboticArmPanel('Line ' + context, 'R1-' + context);
  }
  if (id === 'p-generic-line' && context) {
    target.innerHTML = "<div class=\"hier-breadcrumb\"><span>Line ".concat(context, "</span></div><div class=\"page-title\">Line ").concat(context, "</div><div class=\"page-subtitle\" style=\"margin-bottom:16px\">4 Machines \u2014 Click Robotic Arm to inspect</div><div class=\"kpi-mini-grid\"><div class=\"kpi-mini\" style=\"--kc:#059669\"><div class=\"kpi-mini-val\">96.8%</div><div class=\"kpi-mini-label\">Availability</div></div><div class=\"kpi-mini\" style=\"--kc:#2563EB\"><div class=\"kpi-mini-val\">4</div><div class=\"kpi-mini-label\">Machines</div></div><div class=\"kpi-mini\" style=\"--kc:#D97706\"><div class=\"kpi-mini-val\">2</div><div class=\"kpi-mini-label\">PM Due</div></div><div class=\"kpi-mini\" style=\"--kc:#DC2626\"><div class=\"kpi-mini-val\">0</div><div class=\"kpi-mini-label\">Breakdown</div></div></div>") + buildRoboticArmPanel('Line ' + context, 'generic-' + context);
  }
  if (id === 'p-mach-plant' && context) {
    target.innerHTML = "<div class=\"hier-breadcrumb\"><span class=\"hier-bc-item\" onclick=\"selectPanel('p-machining')\">\u2699\uFE0F Machining</span><span class=\"hier-bc-sep\">\u203A</span><span>".concat(context, "</span></div><div class=\"page-title\">").concat(context, "</div><div class=\"page-subtitle\" style=\"margin-bottom:16px\">18 Lines \xB7 4 Machines each</div><div class=\"kpi-mini-grid\"><div class=\"kpi-mini\" style=\"--kc:#2563EB\"><div class=\"kpi-mini-val\">18</div><div class=\"kpi-mini-label\">Lines</div></div><div class=\"kpi-mini\" style=\"--kc:#059669\"><div class=\"kpi-mini-val\">94.8%</div><div class=\"kpi-mini-label\">PM Compliance</div></div></div>");
  }
}
function switchMachine(line, mach, btn) {
  var panel = document.getElementById('p-' + line);
  panel.querySelectorAll('.machine-tab').forEach(function (t) {
    return t.classList.remove('active');
  });
  panel.querySelectorAll('.machine-panel').forEach(function (p) {
    return p.classList.remove('active');
  });
  btn.classList.add('active');
  document.getElementById('mp-' + line + '-' + mach).classList.add('active');
  // Lazy render
  var inner = document.getElementById('p-' + line + '-' + mach + '-inner');
  if (inner && !inner.dataset.rendered) {
    inner.innerHTML = getMachineHTML(line, mach);
    inner.dataset.rendered = '1';
  }
}
